import React, { useState } from 'react';
import { Link, useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import authService, { RegisterData } from '../services/authService';

const Register: React.FC = () => {
  const navigate = useNavigate();
  const { login } = useAuth();

  const [formData, setFormData] = useState<RegisterData>({
    username: '',
    email: '',
    password: '',
    password_confirm: '',
    first_name: '',
    last_name: '',
    role: 'INTERIOR_DESIGNER',
    phone_number: '',
  });

  const [errors, setErrors] = useState<Record<string, string>>({});
  const [isLoading, setIsLoading] = useState(false);
  const [successMessage, setSuccessMessage] = useState('');

  const handleChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
    // Clear error for this field when user starts typing
    if (errors[name]) {
      setErrors(prev => ({ ...prev, [name]: '' }));
    }
  };

  const validateForm = (): boolean => {
    const newErrors: Record<string, string> = {};

    // Username validation
    if (!formData.username) {
      newErrors.username = 'Username is required';
    } else if (!/^[a-zA-Z0-9_]{3,150}$/.test(formData.username)) {
      newErrors.username = 'Username must be 3-150 characters and contain only letters, numbers, and underscores';
    }

    // Email validation
    if (!formData.email) {
      newErrors.email = 'Email is required';
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(formData.email)) {
      newErrors.email = 'Please enter a valid email address';
    }

    // Password validation
    if (!formData.password) {
      newErrors.password = 'Password is required';
    } else if (formData.password.length < 8) {
      newErrors.password = 'Password must be at least 8 characters';
    } else if (!/(?=.*[a-z])(?=.*[A-Z])(?=.*\d)/.test(formData.password)) {
      newErrors.password = 'Password must include uppercase, lowercase, and number';
    }

    // Password confirmation
    if (formData.password !== formData.password_confirm) {
      newErrors.password_confirm = 'Passwords do not match';
    }

    // Name validation
    if (!formData.first_name) {
      newErrors.first_name = 'First name is required';
    }
    if (!formData.last_name) {
      newErrors.last_name = 'Last name is required';
    }

    // Phone validation (optional but must be valid if provided)
    if (formData.phone_number && !/^\+254[17]\d{8}$|^07\d{8}$/.test(formData.phone_number)) {
      newErrors.phone_number = 'Phone must be in Kenyan format (+254XXXXXXXXX or 07XXXXXXXX)';
    }

    setErrors(newErrors);
    return Object.keys(newErrors).length === 0;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();

    if (!validateForm()) {
      return;
    }

    setIsLoading(true);
    setErrors({});
    setSuccessMessage('');

    try {
      const response = await authService.register(formData);

      if (response.success) {
        setSuccessMessage('Account created successfully! Redirecting to login...');

        // Redirect to login page with success flag
        setTimeout(() => {
          navigate('/login?registered=true');
        }, 2000);
      } else {
        // Handle unsuccessful response
        setErrors({
          general: response.message || 'Registration failed. Please try again.'
        });
      }
    } catch (error: any) {
      console.error('Registration error:', error);
      console.error('Error details:', error.response?.data);

      // Extract error message from different possible formats
      let errorMessage = 'Registration failed. Please try again.';
      const newErrors: Record<string, string> = {};

      if (error.response?.data) {
        const data = error.response.data;

        // Check for field-specific errors
        if (data.errors) {
          // Handle validation errors for specific fields
          Object.keys(data.errors).forEach(field => {
            const fieldError = data.errors[field];
            newErrors[field] = Array.isArray(fieldError) ? fieldError[0] : fieldError;
          });
        }

        // Check for general error messages
        if (data.message) {
          errorMessage = data.message;

          // Try to assign to specific field if message mentions it
          if (errorMessage.toLowerCase().includes('email')) {
            newErrors.email = errorMessage;
          } else if (errorMessage.toLowerCase().includes('username')) {
            newErrors.username = errorMessage;
          } else {
            newErrors.general = errorMessage;
          }
        } else if (data.detail) {
          newErrors.general = data.detail;
        } else if (Object.keys(newErrors).length === 0) {
          newErrors.general = errorMessage;
        }
      } else if (error.message) {
        // Handle specific error messages from error.message
        if (error.message.toLowerCase().includes('email')) {
          newErrors.email = error.message;
        } else if (error.message.toLowerCase().includes('username')) {
          newErrors.username = error.message;
        } else {
          newErrors.general = error.message;
        }
      } else {
        newErrors.general = errorMessage;
      }

      setErrors(newErrors);
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-amber-50 to-amber-100 py-12 px-4 sm:px-6 lg:px-8">
      <div className="max-w-md mx-auto">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-3xl font-bold text-gray-900 mb-2">
            Create Your Account
