              {/* Availability Badge */}
              <div className="mb-6">
                {isInStock && (
                  <span className="inline-flex items-center gap-2 px-4 py-2 rounded-full text-sm font-medium bg-green-100 text-green-800 border border-green-200">
                    <CheckmarkFilled size={16} />
