28 |   (response) => response,
29 |   async (error: AxiosError) => {
30 |     const originalRequest = error.config as InternalAxiosRequestConfig & { _retry?: boolean };
31 | 
32 |     if (error.response?.status === 401 && !originalRequest._retry) {
33 |       originalRequest._retry = true;
34 | 
